        return;
    }

    let start_addr = self.address;
    let mut label = None;
    let mut instruction_part = line;

    // Check for label (must be on its own line, matching reference as24)
    if let Some(colon_pos) = line.find(':') {
        let label_str = line[..colon_pos].trim();
