354	    n = sizeof(instab)/sizeof(struct insdef);
355	    while (i < n) {
356	
357	        /* Skip over directives */
358	        if (instab[i].code < 0) {
359	            ++i;
360	            continue;
361	        }
362	
363	        /* Instructions */
364	        if (instab[i].code == inst->bytes[0]) {
365	            j = 0;
366	            while ((j < 4) && instab[i].toks[j][0]) {
367	                if ((j == 2) && !z) {
368	                    strcpy(EOBUF(obuf), ",");
369	                }
370	                if (d && (j == (d + 1))) {
371	                    strcpy(EOBUF(obuf), "(");
372	                }
373	                if (!strcmp(instab[i].toks[j], "0")) {
374	                    d = j;
375	                    z = 1;
376	                    ++j;
377	                    continue;
378	                }
379	                if ((j && (instab[i].toks[j][0] == 'd')) || \
380	                    (j && ((instab[i].toks[j][0] == 'i') && \
381	                           isdigit(instab[i].toks[j][1]))) || \
382	                    (j && !strcmp(instab[i].toks[j], "o8")) || \
383	                    (j && (instab[i].toks[j][0] == 'u'))) {
384	                    if (inst->fixtype) {
385	                        strcpy(EOBUF(obuf), inst->symref);
386	                    } else {
387	                        if (instab[i].toks[j][1] == '8') {
388	                            d = j;
389	                            if (instab[i].toks[j][0] == 'u') {
390	                                dimm = (uint8_t)inst->bytes[1];
391	                            } else {
392	                                dimm = (int8_t)inst->bytes[1];
393	                            }
394	                        } else {
395	                            dimm = inst->bytes[1] << 0;
396	                            dimm += inst->bytes[2] << 8;
397	                            dimm += inst->bytes[3] << 16;
398	                            if (instab[i].toks[j][0] == 'i') {
399	                                dimm = ((int32_t)dimm << 8) >> 8;
400	                            }
401	                        }
402	                        if (strcmp(instab[i].toks[j], "o8") || dimm) {
403	                            sprintf(EOBUF(obuf), "%d", dimm);
404	                        }
405	                    }
406	                } else {
407	                    strcpy(EOBUF(obuf), instab[i].toks[j]);
408	                }
409	                if (!j) {
410	                    strcpy(EOBUF(obuf), "\t");
411	                }
412	                if (d && (j == (d + 1))) {
413	                    strcpy(EOBUF(obuf), ")");
414	                }
415	
416	                ++j;
417	            }
418	
419	            return;
420	        }
421	
422	        ++i;
423	    }
424	
425	    sprintf(obuf, "? Line %d: unknown instruction code: %02x",
426	            inst->lineno, inst->bytes[0]);
427	    error = 1;
428	}
