430	/* Scan strings for numbers */
431	static int scani32(s, pi32)
432	char *s;
433	int32_t *pi32;
434	{
435	    char extra[TOKLEN];
436	
437	    if (isdigit(s[0]) && (s[strlen(s) - 1] == 'h')) {
438	        if (!(sscanf(s, "%x", pi32) == 1)) {
439	            return 0;
440	        }
441	    } else {
442	        if (!(sscanf(s, "%d%s", pi32, &extra[0]) == 1)) {
443	            return 0;
444	        }
445	    }
446	
447	    return 1;
448	}
449	static int scani8(s, pi32)
450	char *s;
451	int32_t *pi32;
452	{
453	    if (!scani32(s, pi32)) {
454	        return 0;
455	    }
456	    if ((*pi32 < -128) || (127 < *pi32)) {
457	        return 0;
458	    }
459	
460	    return 1;
461	}
462	static int scanu8(s, pi32)
463	char *s;
464	int32_t *pi32;
465	{
466	    if (!scani32(s, pi32)) {
467	        return 0;
468	    }
469	    if ((*pi32 < 0) || (255 < *pi32)) {
470	        return 0;
471	    }
472	
473	    return 1;
474	}
475	static int scani24(s, pi32)
476	char *s;
477	int32_t *pi32;
478	{
479	    if (!scani32(s, pi32)) {
480	        return 0;
481	    }
482	    if ((*pi32 < -(1 << 24)) || !(*pi32 < (1 << 24))) {
483	        return 0;
484	    }
485	
486	    return 1;
487	}
