539	/* Assemble instructions, process labels and directives */
540	static struct insform *findins(lineno)
541	uint32_t lineno;
542	{
543	    int i, j, k, n;
544	    uint32_t dimm;
545	    struct insform *svp;
546	
547	    /* Clear the form, set the section and line numbers */
548	    memset(tmpf, 0, sizeof(struct insform));
549	    tmpf->lineno = lineno;
550	    tmpf->section = secnum;
551	
552	    /* Is there a comment on the line ? */
553	    i = 0;
554	    while ((i < LINSIZ) && linebuf[i] && !(linebuf[i] == '\n')) {
555	        if (linebuf[i] == ';') {
556	            break;
557	        }
558	        ++i;
559	    }
560	    if ((i < LINSIZ) && (linebuf[i] == ';')) {
561	        tmpf->comment = (char *)malloc(strlen(&linebuf[i]) + 1);
562	        if (!tmpf->comment) {
563	            fprintf(stderr, "? Line %d: malloc failed\n", lineno);
564	            error = 1;
565	            return NULL;
566	        }
567	        strcpy(tmpf->comment, &linebuf[i]);
568	    }
569	
570	    /* Full line comment ? */
571	    if (ntokens < 0) {
572	        tmpf->fixtype = FIXCMNT;
573	        return tmpf;
574	    }
575	
576	    /* Is it a label or symbol definition ? */
577	    n = strlen(tokens[0]) - 1; 
578	    if ((ntokens == 1) && (tokens[0][n] == ':')) {
579	        tmpf->fixtype = FIXLABL;
580	        strncpy(tmpf->symref, tokens[0], n);
581	        tmpf->symref[n] = '\0';
582	        if (dupsym(tmpf->symref, lineno)) {
583	            return NULL;
584	        }
585	        return tmpf;
586	    }        
587	    if ((ntokens == 3) && !isdigit(tokens[0][0]) && isdigit(tokens[2][0]) &&
588	        (tokens[1][0] == '=') && scani24(tokens[2], &dimm)) {
589	        if (dupsym(tokens[0], lineno)) {
590	            return NULL;
591	        }
592	        tmpf->fixtype = FIXSYMB;
593	        strcpy(tmpf->symref, tokens[0]);
594	        tmpf->symval = dimm;
595	        return tmpf;
596	    }
597	
598	    /* Bump location counter */
599	    if ((ntokens == 5) && (tokens[0][0] == '.') && (tokens[1][0] == '=') &&
600	        (tokens[2][0] == '.') && (tokens[3][0] == '+') &&
601	        scani24(tokens[4], &dimm)) {
602	        tmpf->fixtype = FIXBUMP;
603	        tmpf->length = dimm;
604	        return tmpf;
605	    }
606	
607	    /* Look for it in table */
608	    n = sizeof(instab)/sizeof(struct insdef);
609	    i = 0;
610	    while (i < n) {
611	
612	        /* No match on first token */
613	        if (strcmp(instab[i].toks[0], tokens[0])) {
614	            ++i;
615	            continue;
616	        }
617	
618	        /* Directives */
619	        if (instab[i].code < 0) {
620	
621	            /* .bss */
622	            if (!strcmp(tokens[0], ".bss")) {
623	                tmpf->fixtype = FIXOTHR;
624	                secnum = 2;
625	                tmpf->section = -1;
626	                return tmpf;
627	            }
628	
629	            /* .byte */
630	            if (!strcmp(tokens[0], ".byte")) {
631	                k = 0;
632	                while (k < (ntokens - 1)) {
633	                    if (!scanu8(tokens[k + 1], &dimm)) {
634	                        break;
635	                    }
636	                    tmpf->bytes[k] = (uint8_t)dimm;
637	                    ++k;
638	                }
639	                if (k < (ntokens - 1)) {
640	                    ++i;
641	                    continue;
642	                }
643	                tmpf->fixtype = FIXBDAT;
644	                tmpf->length = k;
645	                return tmpf;
646	            }
647	
648	            /* .comm */
649	            if (!strcmp(tokens[0], ".comm")) {
650	                if (!(ntokens == 3) || isdigit(tokens[1][0]) ||
651	                    !scani24(tokens[2], &dimm)) {
652	                    ++i;
653	                    continue;
654	                }
655	                if ((svp = symfind(tokens[1]))) {
656	                    if ((svp->fixtype == FIXCOMM) && (svp->length < dimm)) {
657	                        svp->length = dimm;
658	                    }
659	                    return NULL;
660	                }
661	                tmpf->fixtype = FIXCOMM;
662	                tmpf->length = dimm;
663	                strcpy(tmpf->symref, tokens[1]);
664	                return tmpf;
665	            }
666	
667	            /* .data */
668	            if (!strcmp(tokens[0], ".data")) {
669	                tmpf->fixtype = FIXOTHR;
670	                secnum = 1;
671	                tmpf->section = -1;
672	                return tmpf;
673	            }
674	
675	            /* .globl */
676	            if (!strcmp(tokens[0], ".globl")) {
677	                tmpf->fixtype = FIXOTHR;
678	                strcpy(tmpf->symref, tokens[0]);
679	                strcpy((char *)tmpf->bytes, tokens[1]);
680	                return tmpf;
681	            }
682	
683	            /* .text */
684	            if (!strcmp(tokens[0], ".text")) {
685	                tmpf->fixtype = FIXOTHR;
686	                secnum = 0;
687	                tmpf->section = -1;
688	                return tmpf;
689	            }
690	
691	            /* .word */
692	            if (!strcmp(tokens[0], ".word")) {
693	                k = 0;
694	                while (k < (ntokens - 1)) {
695	                    if (!scani24(tokens[k + 1], &dimm)) {
696	                        break;
697	                    }
698	                    tmpf->bytes[k*3 + 0] = (uint8_t)(dimm >> 0);
699	                    tmpf->bytes[k*3 + 1] = (uint8_t)(dimm >> 8);
700	                    tmpf->bytes[k*3 + 2] = (uint8_t)(dimm >> 16);
701	                    ++k;
702	                }
703	                if (!(k < (ntokens - 1))) {
704	                    memset(&tmpf->bytes[k*3], 0, sizeof(tmpf->bytes) - k*3);
705	                    tmpf->fixtype = FIXWDAT;
706	                    tmpf->length = k*3;
707	                    return tmpf;
708	                }
709	
710	                tmpf->fixtype = FIXDD24;
711	                tmpf->length = 3;
712	                strcpy(tmpf->symref, tokens[1]);
713	                return tmpf;
714	            }
715	
716	            tmpf->fixtype = FIXOTHR;
717	            strcpy(tmpf->symref, tokens[0]);
718	            return tmpf;
719	        }
720	            
721	        /* Instructions */
722	        tmpf->bytes[0] = (uint8_t)instab[i].code;
723	        tmpf->length = 1;
724	        j = 0;
725	        while ((j < 4) && instab[i].toks[j][0]) {
726	            if (!(j < ntokens)) {
727	                break;
728	            }
729	
730	            k = 0;
731	            if (!strcmp(instab[i].toks[j], "i8")) {
732	                tmpf->length = 2;
733	                k = 1;
734	            }
735	            if (!strcmp(instab[i].toks[j], "u8")) {
736	                tmpf->length = 2;
737	                k = 2;
738	            }
739	            if (!strcmp(instab[i].toks[j], "d8")) {
740	                tmpf->length = 2;
741	                k = 3;
742	            }
743	            if (!strcmp(&instab[i].toks[j][1], "24")) {
744	                tmpf->length = 4;
745	                k = 4;
746	            }
747	            if (!strcmp(instab[i].toks[j], "o8")) {
748	                tmpf->length = 2;
749	                k = 5;
750	            }
751	
752	            if (k) {
753	                if (isdigit(tokens[j][0]) || 
754	                    (tokens[j][0] == '-') || (tokens[j][0] == '+')) {
755	                    if ((k == 1) || (k == 3) || (k == 5)) {
756	                        if (!scani8(tokens[j], &dimm)) {
757	                            break;
758	                        }
759	                    }
760	                    if (k == 2) {
761	                        if (!scanu8(tokens[j], &dimm)) {
762	                            break;
763	                        }
764	                    }
765	                    if (k == 4) {
766	                        if (!scani24(tokens[j], &dimm)) {
767	                            break;
768	                        }
769	                        tmpf->bytes[2] = (uint8_t)(dimm >> 8);
770	                        tmpf->bytes[3] = (uint8_t)(dimm >> 16);
771	                    }
772	                    tmpf->bytes[1] = (uint8_t)dimm;
773	                } else {
774	                    if (!((k == 3) || (k == 4))) {
775	                        break;
776	                    }
777	                    switch (k) {
778	                        case 3 :
779	                            tmpf->fixtype = FIXPCD8;
780	                            break;
781	                        case 4 :
782	                            tmpf->fixtype = FIXID24;
783	                            break;
784	                    }
785	                    strcpy(tmpf->symref, tokens[j]);
786	                }
787	            } else {
788	                if (strcmp(tokens[j], instab[i].toks[j])) {
789	                    break;
790	                }
791	            }
792	
793	            ++j;
794	        }
795	
796	        if (!(j < 4) || !instab[i].toks[j][0]) {
797	            break;
798	        }
799	
800	        ++i;
801	    }
802	
803	    if (i < n) {
804	        return tmpf;
805	    }
806	
807	    /* Default word data initialization ? */
808	    if (ntokens == 1) {
809	        if (scani24(tokens[0], &dimm)) {
810	            tmpf->fixtype = FIXWDAT;
811	            tmpf->length = 3;
812	            tmpf->bytes[0] = (uint8_t)(dimm >> 0);
813	            tmpf->bytes[1] = (uint8_t)(dimm >> 8);
814	            tmpf->bytes[2] = (uint8_t)(dimm >> 16);
815	            return tmpf;
816	        }
817	        if (!isdigit(tokens[0][0])) {
818	            tmpf->fixtype = FIXDD24;
819	            tmpf->length = 3;
820	            strcpy(tmpf->symref, tokens[0]);
821	            return tmpf;
822	        }
823	    }
824	
825	    /* Unknown instruction/directive */
826	    fprintf(stderr, "? Line %d: unknown instruction/directive: '", lineno);
827	    i = 0;
828	    while (i < ntokens) {
829	        if (i) {
830	            fputc(' ', stderr);
831	        }
832	        fputs(tokens[i], stderr);
833	        ++i;
834	    }
835	    fputs("'\n", stderr);
836	    error = 1;
837	
838	    return NULL;
839	}
