841	/* Scan a line and get all the tokens */
842	static void scan(lineno)
843	uint32_t lineno;
844	{
845	    char *cp;
846	    int i, t;
847	
848	    cp = linebuf;
849	    ntokens = 0;
850	    i = t = 0;
851	    while (*cp && !(*cp == '\n') && !(*cp == ';')) {
852	        if (!(ntokens < MAXTOKS)) {
853	            fprintf(stderr, "? Line %d: too many tokens\n", lineno);
854	            error = 1;
855	            return;
856	        }
857	        if (isspace(*cp) || (*cp == ',') || (*cp == '(') || (*cp == ')')) {
858	            if (t) {
859	                tokens[ntokens][i] = '\0';
860	                i = t = 0;
861	                ++ntokens;
862	            } else {
863	                if (*cp == '(') {
864	                    tokens[ntokens][0] = '0';
865	                    i = t = 1;
866	                    continue;
867	                }
868	            }
869	            ++cp;
870	            continue; 
871	        }
872	        if (!(i < TOKLEN)) {
873	            tokens[ntokens][TOKLEN] = '\0';
874	            fprintf(stderr, "? Line %d: token '%s ...' too long\n",
875	                    lineno, tokens[ntokens]);
876	            error = 1;
877	            return;
878	        }
879	        t = 1;
880	        tokens[ntokens][i] = *cp;
881	        ++i;
882	        ++cp;
883	    }
884	    if (t) {
885	        tokens[ntokens][i] = '\0';
886	        ++ntokens;
887	    }
888	
889	    if (!ntokens && (*cp == ';')) {
890	        ntokens = -1;
891	    }
892	}
