901	/* Untabify an output string */
902	static void untabify(s)
903	char *s;
904	{
905	    char c, t[LINSIZ];
906	    int i, j, k;
907	
908	    i = j = k = 0;
909	    while ((j < (LINSIZ - 1)) && (c = s[i++])) {
910	        if (c == '\t') {
911	            do {
912	                t[j++] = ' ';
913	                ++k;
914	            } while (k % 8);
915	        } else {
916	            t[j++] = c;
917	            ++k;
918	        }
919	        if (c == '\n') {
920	            k = 0;
921	        }
922	    }
923	    t[j] = '\0';
924	    strcpy(s, t);
925	}
