927	/* Load-and-go script for running program on target */
928	static void lgoput()
929	{
930	    int i;
931	    struct insform *inext, *s;
932	
933	    /* Can't emit load script with errors */
934	    if (error) {
935	        fputs("? Errors, can't generate load script\n", stderr);
936	        return;
937	    }
938	
939	    /* Dump the bytes in load commands */
940	    secnum = curloc = 0;
941	    while (secnum < 3) {
942	        inext = ifirst;
943	        while (inext) {
944	            if (!(inext->section == secnum)) {
945	                inext = inext->next;
946	                continue;
947	            }
948	
949	            if (!(inext->fixtype < 0) || (inext->fixtype == FIXBDAT) || \
950	                (inext->fixtype == FIXWDAT)) {
951	                printf("L%06X", curloc);
952	                i = 0;
953	                while (i < inext->length) {
954	                    printf("%02X", inext->bytes[i]);
955	                    ++i;
956	                }
957	                putchar('\n');
958	            }
959	            curloc += inext->length;
960	            inext = inext->next;
961	        }
962	
963	        ++secnum;
964	    }
965	
966	    /* No input ? */
967	    if (!ifirst || !curloc) {
968	        return;
969	    }
970	
971	    /* Go to "start", if defined */
972	    s = symfind("start");
973	    if (s) {
974	        printf("G%06X\n", s->symval);
975	    }
976	}
