978	/* Assembly listing */
979	#define INSSIZ 32
980	static void lstput()
981	{
982	    char dbuf[INSSIZ], o[LINSIZ];
983	    int i, t;
984	    struct insform *inext;
985	
986	    secnum = curloc = 0;
987	    t = FIXCMNT;
988	    while (secnum < 3) {
989	        inext = ifirst;
990	        while (inext) {
991	            if (!(inext->section == secnum)) {
992	                inext = inext->next;
993	                continue;
994	            }
995	
996	            o[0] = '\0';
997	            switch (inext->fixtype) {
998	                case FIXBDAT :
999	                    i = 0;
1000	                    while (i < inext->length) {
1001	                        if (i) {
1002	                            sprintf(EOBUF(o), "\n");
1003	                        }
1004	                        sprintf(EOBUF(o),
1005	                                "%06x %02x", curloc + i, inext->bytes[i]);
1006	                        ++i;
1007	                    }
1008	                    break;
1009	                case FIXWDAT :
1010	                case FIXDD24 :
1011	                    i = 0;
1012	                    while (i < inext->length) {
1013	                        if (i) {
1014	                            sprintf(EOBUF(o), "\n");
1015	                        }
1016	                        sprintf(EOBUF(o),
1017	                                "%06x %02x %02x %02x", curloc + i,
1018	                               inext->bytes[i + 0], inext->bytes[i + 1], \
1019	                               inext->bytes[i + 2]);
1020	                        i += 3;
1021	                    }
1022	                    break;
1023	                case FIXBUMP :
1024	                case FIXCOMM :
1025	                case FIXLABL :
1026	                    if (!(t < 0)) {
1027	                        sprintf(EOBUF(o), "\n");
1028	                    }
1029	                    if ((inext->fixtype == FIXLABL) ||
1030	                        (inext->fixtype == FIXCOMM)) {
1031	                        sprintf(EOBUF(o), "%s:", inext->symref);
1032	                    }
1033	                    if (inext->fixtype == FIXCOMM) {
1034	                        sprintf(EOBUF(o), "\n");
1035	                    }
1036	                    if ((inext->fixtype == FIXCOMM) ||
1037	                        (inext->fixtype == FIXBUMP)) {
1038	                        sprintf(EOBUF(o), "%06x", curloc);
1039	                    }
1040	                    break;
1041	                case FIXSYMB :
1042	                case FIXOTHR :
