1465	/* Fix "a branch too far" */
1466	static int fixbra(ibra)
1467	struct insform *ibra;
1468	{
1469	    struct insform *ilabel, *ijump;
1470	
1471	    /* If it's an unconditional branch, replace it with a jump */
1472	    if (ibra->bytes[0] == BRA) {
1473	        ibra->bytes[0] = JMPA;
1474	        ibra->bytes[1] = ibra->bytes[2] = ibra->bytes[3] = 0;
1475	        ibra->fixtype = FIXID24;
1476	        ibra->length = 4;
1477	        return 1;
1478	    }
1479	
1480	    /* Conditional - reverse the sense, branch around */
1481	    /* a jump to the target of the original condition */
1482	
1483	    /* Insert a label after the current branch */
1484	    ilabel = insinst(ibra, ibra->next);
1485	    if (!ilabel) {
1486	        return 0;
1487	    }
1488	    ilabel->fixtype = FIXLABL;
1489	    sprintf(ilabel->symref, "L%d", labeln++);
1490	
1491	    /* Then insert a jump before the label */
1492	    ijump = insinst(ibra, ilabel);
1493	    if (!ijump) {
1494	        return 0;
1495	    }
1496	    strcpy(ijump->symref, ibra->symref);
1497	    ijump->bytes[0] = JMPA;
1498	    ijump->bytes[1] = ibra->bytes[2] = ibra->bytes[3] = 0;
1499	    ijump->fixtype = FIXID24;
1500	    ijump->length = 4;
1501	
1502	    /* Now change the sense and the target of the original branch */
1503	    ibra->bytes[0] = (ibra->bytes[0] == BRT) ? BRF : BRT;
1504	    strcpy(ibra->symref, ilabel->symref);
1505	
1506	    return 1;
1507	}
