1719	        while (inext) {
1720	            if (!(inext->fixtype < 0) && (inext->bytes[0] == SUBSP)) {
1721	                if ((inext->bytes[1] < 129) && !inext->bytes[2] && \
1722	                    !inext->bytes[3]) {
1723	                    inext->bytes[0] = ADDSP;
1724	                    inext->bytes[1] = -(int8_t)inext->bytes[1];
1725	                    inext->length = 2;
1726	                    inext->bytes[2] = inext->bytes[3] = 0;
1727	                    inext->fixtype = 0;
1728	                    inext->symref[0] = '\0';
1729	                    inext->symval = 0;
1730	                    goto again;
1731	                }
1732	            }
1733	            ilast = inext;
1734	            inext = inext->next;
1735	        }
1736	
1737	        /* Turn a pair of adds to SP, into one, if possible */
1738	        ilast = inext = ifirst;
1739	        while (inext) {
1740	            if ((ilast->fixtype == FIXINST) && (inext->fixtype == FIXINST) && \
1741	                (ilast->bytes[0] == ADDSP) && (inext->bytes[0] == ADDSP)) {
1742	                d = (int8_t)ilast->bytes[1] + (int8_t)inext->bytes[1];
1743	                if ((d < 128) && !(d < -128)) {
1744	                    ilast->bytes[1] = (uint8_t)d;
1745	                    delinst(ilast, inext);
1746	                    goto again;
1747	                }
1748	            }
1749	            ilast = inext;
1750	            inext = inext->next;
1751	        }
1752	
1753	        /* Delete add sp,0 */
1754	        ilast = inext = ifirst;
1755	        while (inext) {
1756	            if (!(inext->fixtype < 0) && (inext->bytes[0] == ADDSP)) {
1757	                if (!inext->bytes[1]) {
1758	                    delinst(ilast, inext);
1759	                    goto again;
1760	                }
1761	            }
1762	            ilast = inext;
1763	            inext = inext->next;
1764	        }
1765	
1766	        /* Add to SP followed by mov sp,fp - skip the add */
1767	        ilast = inext = ifirst;
1768	        while (inext) {
1769	            if ((ilast->fixtype == FIXINST) && (inext->fixtype == FIXINST) && \
1770	                (ilast->bytes[0] == ADDSP) && (inext->bytes[0] == MOVSPFP)) {
1771	                ilast->bytes[0] = MOVSPFP;
1772	                ilast->length = 1;
1773	                delinst(ilast, inext);
1774	                goto again;
1775	            }
1776	            ilast = inext;
1777	            inext = inext->next;
1778	        }
1779	
1780	        /* Conditional branch around unconditional branch ... */
1781	        ilast = inext = ifirst;
1782	        while (inext) {
1783	
1784	            /* ... becomes conditional branch with reversed sense */
1785	            if ((ilast->fixtype == FIXPCD8) && \
1786	                (inext->fixtype == FIXPCD8) && !ilast->bytes[1] && \
1787	                (((ilast->bytes[0] == BRF) && (inext->bytes[0] == BRA)) || \
1788	                 ((ilast->bytes[0] == BRT) && (inext->bytes[0] == BRA)))) {
1789	                ilast->bytes[0] = (ilast->bytes[0] == BRT) ? BRF : BRT;
1790	                strcpy(ilast->symref, inext->symref);
1791	                delinst(ilast, inext);
1792	                goto again;
1793	            }
1794	            ilast = inext;
1795	            inext = inext->next;
1796	        }
1797	
1798	        /* Branch to unconditional branch ... */
1799	        inext = ifirst;
1800	        while (inext) {
1801	
1802	            /* ... becomes branch to second branch's target */
1803	            if ((inext->fixtype == FIXPCD8) && \
1804	                ((inext->bytes[0] == BRA) || (inext->bytes[0] == BRF) || \
1805	                 (inext->bytes[0] == BRT))) {
1806	                ilast = ifirst;
1807	                while (ilast) {
1808	                    if ((ilast->fixtype == FIXLABL) && \
1809	                        !strcmp(inext->symref, ilast->symref)) {
1810	                        while (ilast && ilast->next && \
1811	                               (ilast->next->fixtype == FIXCMNT)) {
1812	                            ilast = ilast->next;
1813	                        }
1814	                        if (ilast && ilast->next && \
1815	                            ((ilast->next->fixtype == FIXPCD8) && \
1816	                             (ilast->next->bytes[0] == BRA))) {
1817	
1818	                            /* But only if something would change */
1819	                            if (strcmp(inext->symref, ilast->next->symref)) {
1820	                                strcpy(inext->symref, ilast->next->symref);
1821	                                goto again;
1822	                            }
1823	                        }
1824	                    }
1825	                    ilast = ilast->next;
1826	                }
1827	            }
1828	            inext = inext->next;
1829	        }
1830	
1831	        /* Remove instructions in the shadow of an unconditional branch */
1832	        ilast = inext = ifirst;
1833	        while (inext) {
1834	            if (!(ilast->fixtype < 0) && \
1835	                (!(inext->fixtype < 0) || (inext->fixtype == FIXCMNT)) \
1836	                && (ilast->bytes[0] == BRA)) {
1837	                delinst(ilast, inext);
1838	                goto again;
1839	            }
1840	            ilast = inext;
1841	            inext = inext->next;
1842	        }
1843	
1844	        /* Remove unreferenced local labels and symbols */
1845	        ilast = inext = ifirst;
1846	        while (inext) {
1847	            if (((inext->fixtype == FIXLABL) && (inext->symref[0] == 'L')) || \
1848	                (inext->fixtype == FIXSYMB)) {
1849	                if (!inext->refcnt) {
1850	                    delinst(ilast, inext);
1851	                    goto again;
1852	                }
1853	            }
1854	            ilast = inext;
1855	            inext = inext->next;
1856	        }
1857	
1858	        /* Change nonzero test, complement C, to just zero test */
1859	        ilast = inext = ifirst;
1860	        while (inext) {
1861	            if ((ilast->fixtype == FIXINST) && (inext->fixtype == FIXINST)) {
1862	                src = srczulr(ilast->bytes[0]);
1863	                dst = dstmovc(inext->bytes[0]);
1864	                if ((inext->next && (inext->next->fixtype == FIXINST) && \
1865	                     inext->next->next) && \
1866	                    (inext->next->next->fixtype == FIXINST)) {
1867	                    src2 = srcreqz(inext->next->bytes[0]);
1868	                    dst2 = dstmovc(inext->next->next->bytes[0]);
1869	                } else {
1870	                    src2 = dst2 = -1;
1871	                }
1872	                if (!(dst < 0) && !(dst2 < 0) && !(src < 0) && \
1873	                    !(src2 < 0) && (dst == src2) && (dst == dst2)) {
1874	                    ilast->bytes[0] = makceq(src);
1875	                    delinst(inext, inext->next);
1876	                    delinst(ilast, inext);
1877	                    goto again;
1878	                }
1879	            }
1880	            ilast = inext;
1881	            inext = inext->next;
1882	        }
1883	
1884	        /* After move to register from C, delete sign or zero extension */
1885	        ilast = inext = ifirst;
1886	        while (inext) {
1887	            if ((ilast->fixtype == FIXINST) && (inext->fixtype == FIXINST)) {
1888	                switch (ilast->bytes[0]) {
1889	                    case MOV_R0_C :
1890	                        if ((inext->bytes[0] == SXT_R0_R0) || \
1891	                            (inext->bytes[0] == ZXT_R0_R0)) {
1892	                            delinst(ilast, inext);
1893	                            goto again;
1894	                        }
1895	                        break;
1896	                    case MOV_R1_C :
1897	                        if ((inext->bytes[0] == SXT_R1_R1) || \
1898	                            (inext->bytes[0] == ZXT_R1_R1)) {
1899	                            delinst(ilast, inext);
1900	                            goto again;
1901	                        }
1902	                        break;
1903	                    case MOV_R2_C :
1904	                        if ((inext->bytes[0] == SXT_R2_R2) || \
1905	                            (inext->bytes[0] == ZXT_R2_R2)) {
1906	                            delinst(ilast, inext);
1907	                            goto again;
1908	                        }
1909	                        break;
1910	                }
1911	            }
1912	            ilast = inext;
1913	            inext = inext->next;
1914	        }
1915	
1916	        /* Change move to src from C, move dst,src, to move to dst from C */
1917	        ilast = inext = ifirst;
1918	        while (inext) {
1919	            if ((ilast->fixtype == FIXINST) && (inext->fixtype == FIXINST)) {
1920	                dst = dstmovc(ilast->bytes[0]);
1921	                src = srcmovr(inext->bytes[0]);
1922	                if (!(dst < 0) && !(src < 0) && (dst == src)) {
1923	                    dst = dstmovr(inext->bytes[0]);
1924	                    ilast->bytes[0] = makmovc(dst);
1925	                    ilast->length = 1;
1926	                    delinst(ilast, inext);
1927	                    goto again;
1928	                }
1929	            }
1930	            ilast = inext;
1931	            inext = inext->next;
1932	        }
1933	    }
1934	
1935	    /* Put out finished code */
1936	    if (lstout) {
1937	        lstput();
1938	    } else {
1939	        if (objout) {
1940	            objput();
1941	        } else {
1942	            if (asmout) {
1943	                asmput(afmt);
1944	            } else {
1945	                lgoput();
1946	            }
1947	        }
1948	    }
1949	
1950	    /* Release instruction/data forms */
1951	    while (ifirst) {
1952	        if (ifirst->comment) {
1953	            free(ifirst->comment);
1954	        }
1955	        inext = ifirst->next;
1956	        free(ifirst);
1957	        ifirst = inext;
1958	    }
1959	
1960	    return error;
1961	}
